import React, { useState, useEffect } from 'react';
import API from '../api/axios';

const RoleMaster = () => {
    const [roles, setRoles] = useState([]);
    const [formData, setFormData] = useState({ roleName: '', description: '' });
    const [loading, setLoading] = useState(false);

    const roleOptions = ['SuperAdmin', 'User', 'Networking Staff', 'Plumber', 'Electrician', 'Software Developer'];

    useEffect(() => {
        fetchRoles();
    }, []);

    const fetchRoles = async () => {
        try {
            const { data } = await API.get('/master/role');
            setRoles(data);
        } catch (err) {
            alert('Error fetching roles');
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            await API.post('/master/role', formData);
            setFormData({ roleName: '', description: '' });
            fetchRoles();
            alert('Role added successfully!');
        } catch (err) {
            alert('Error adding role');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={{ padding: '40px', color: 'white', background: '#0f172a', minHeight: '100vh' }}>
            <h2 style={{ fontSize: '2rem', marginBottom: '30px' }}>Role Master</h2>
            
            <form onSubmit={handleSubmit} style={{ maxWidth: '500px', marginBottom: '40px' }}>
                <div style={{ marginBottom: '15px' }}>
                    <label>Role Name</label>
                    <select 
                        required
                        value={formData.roleName}
                        onChange={e => setFormData({...formData, roleName: e.target.value})}
                        style={inputStyle}
                    >
                        <option value="">Select Role</option>
                        {roleOptions.map(role => (
                            <option key={role} value={role}>{role}</option>
                        ))}
                    </select>
                </div>
                
                <div style={{ marginBottom: '15px' }}>
                    <label>Description (Optional)</label>
                    <textarea 
                        value={formData.description}
                        onChange={e => setFormData({...formData, description: e.target.value})}
                        style={{...inputStyle, height: '80px'}}
                        placeholder="Enter role description..."
                    />
                </div>

                <button type="submit" disabled={loading} style={btnStyle}>
                    {loading ? 'Adding...' : 'Add Role'}
                </button>
            </form>

            <h3>Roles List</h3>
            <table style={tableStyle}>
                <thead>
                    <tr>
                        <th>Role Name</th>
                        <th>Description</th>
                    </tr>
                </thead>
                <tbody>
                    {roles.map(role => (
                        <tr key={role._id}>
                            <td>{role.roleName}</td>
                            <td>{role.description}</td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

const inputStyle = { 
    width: '100%', 
    padding: '10px', 
    marginTop: '5px',
    borderRadius: '5px', 
    border: '1px solid #334155', 
    background: '#1e293b', 
    color: 'white',
    boxSizing: 'border-box'
};

const btnStyle = { 
    padding: '12px 20px', 
    background: 'linear-gradient(to right, #38bdf8, #818cf8)', 
    border: 'none', 
    borderRadius: '5px', 
    color: 'white', 
    fontWeight: 'bold', 
    cursor: 'pointer',
    width: '100%'
};

const tableStyle = {
    width: '100%',
    borderCollapse: 'collapse',
    marginTop: '20px',
    border: '1px solid #334155'
};

export default RoleMaster;
